     and 1 = 0
     and t.user_id = #{userId}
     and t.message_title like concat('%', #{messageTitle}, '%')
     and t.read_status = #{readStatus}

        and (
            exists (
                select 1
                from edu_course c
                where t.course_id is not null
                  and c.course_id = t.course_id
                  and c.dept_id = #{params.scopeDeptId}
                  and (c.del_flag is null or c.del_flag = '0')
            )
            or exists (
                select 1
                from sys_user u
                where u.user_id = t.user_id
                  and u.dept_id = #{params.scopeDeptId}
            )
        )


        and (
            t.sender_user_id = #{params.scopeTeacherUserId}
            or exists (
                select 1
                from edu_course_teacher ct
                where t.course_id is not null
                  and ct.course_id = t.course_id
                  and ct.teacher_user_id = #{params.scopeTeacherUserId}
            )
            or exists (
                select 1
                from edu_course_enrollment e
                join edu_course_teacher ct on ct.course_id = e.course_id
                where e.student_user_id = t.user_id
                  and ct.teacher_user_id = #{params.scopeTeacherUserId}
            )
        )


order by t.message_id desc

