user_id = #{userId}, course_id = #{courseId}, assignment_id = #{assignmentId}, notice_id = #{noticeId}, biz_type = #{bizType}, message_title = #{messageTitle}, message_content = #{messageContent}, sender_user_id = #{senderUserId}, send_time = #{sendTime}, read_status = #{readStatus}, read_time = #{readTime}, link_path = #{linkPath}, expire_time = #{expireTime}, create_by = #{createBy}, create_time = #{createTime}, update_by = #{updateBy}, update_time = #{updateTime}, remark = #{remark},
